// // This module converts a 4-bit binary input into its corresponding Binary-Coded Decimal (BCD) output representation. However, it incorrectly maps values from 10 to 15 to the lower nibble instead of the upper nibble.
module top_module(input [3:0] A, output reg [7:0] Z);always @(*) begin
    case(A)
      4'b0000: Z = 8'b0000_0000;
      4'b0001: Z = 8'b0000_0001;
      4'b0010: Z = 8'b0000_0010;
      4'b0011: Z = 8'b0000_0011;
      4'b0100: Z = 8'b0000_0100;
      4'b0101: Z = 8'b0000_0101;
      4'b0110: Z = 8'b0000_0110;
      4'b0111: Z = 8'b0000_0111;
      4'b1000: Z = 8'b0000_1000;
      4'b1001: Z = 8'b0000_1001;
      4'b1010: Z = 8'b0001_0000;
      4'b1011: Z = 8'b0001_0001;
      4'b1100: Z = 8'b0001_0010;
      4'b1101: Z = 8'b0001_0011;
      4'b1110: Z = 8'b0001_0100;
      4'b1111: Z = 8'b0001_0101;
      default: Z = 8'b0000_0000;
    endcase
  end

endmodule
